+static int decode_sign_ext(arm64_extender extender) {
+	switch (extender) {
+	case ARM64_EXT_UXTB:
+	case ARM64_EXT_UXTH:
+	case ARM64_EXT_UXTW:
+	case ARM64_EXT_UXTX:
+		return 0; // nothing needs to be done for unsigned
+	case ARM64_EXT_SXTB:
+		return 8;
+	case ARM64_EXT_SXTH:
+		return 16;
+	case ARM64_EXT_SXTW:
+		return 32;
+	case ARM64_EXT_SXTX:
+		return 64;
+	default:
+		break;
+	}
+
+	return 0;
+}
