+		break;
+	}
+	case ARM_INS_TBB:
+		r_strbuf_appendf (&op->esil, "%s,%s,+,0xffffffff,&,DUP,[1],1,SWAP,<<,+,pc,+=",
+			MEMBASE (0), MEMINDEX (0));
+		break;
+	case ARM_INS_TBH:
+		r_strbuf_appendf (&op->esil, "%s,%d,%s,<<,+,0xffffffff,&,[2],1,SWAP,<<,pc,+=",
+			MEMBASE (0), LSHIFT2 (0), MEMINDEX (0));
+		break;
+	default:
+		break;
+	}
+	// Update flags if required...TODO different instructions update different flags, but this should fix
+	// many errors
+	if (insn->detail->arm.update_flags) {
+		switch(insn->id) {
+		case ARM_INS_CMP:
+			r_strbuf_append (&op->esil, ",$z,zf,:=,31,$s,nf,:=,32,$b,!,cf,:=,31,$o,vf,:=");
+			break;
+		case ARM_INS_ADD:
+		case ARM_INS_RSB:
+		case ARM_INS_SUB:
+		case ARM_INS_SBC:
+		case ARM_INS_ADC:
+		case ARM_INS_CMN:
+			r_strbuf_append (&op->esil, ",$z,zf,:=,31,$s,nf,:=,31,$c,cf,:=,31,$o,vf,:=");
+			break;
+		default:
+			r_strbuf_append (&op->esil, ",$z,zf,:=,31,$s,nf,:=");
+		}
+	}
+
+	r_strbuf_append (&op->esil, postfix);
+
+	return 0;
+}
+
+static int cond_cs2r2(int cc) {
+	if (cc == ARM_CC_AL || cc < 0) {
+		cc = R_ANAL_COND_AL;
+	} else {
+		switch (cc) {
+		case ARM_CC_EQ: cc = R_ANAL_COND_EQ; break;
+		case ARM_CC_NE: cc = R_ANAL_COND_NE; break;
+		case ARM_CC_HS: cc = R_ANAL_COND_HS; break;
+		case ARM_CC_LO: cc = R_ANAL_COND_LO; break;
+		case ARM_CC_MI: cc = R_ANAL_COND_MI; break;
+		case ARM_CC_PL: cc = R_ANAL_COND_PL; break;
+		case ARM_CC_VS: cc = R_ANAL_COND_VS; break;
+		case ARM_CC_VC: cc = R_ANAL_COND_VC; break;
+		case ARM_CC_HI: cc = R_ANAL_COND_HI; break;
+		case ARM_CC_LS: cc = R_ANAL_COND_LS; break;
+		case ARM_CC_GE: cc = R_ANAL_COND_GE; break;
+		case ARM_CC_LT: cc = R_ANAL_COND_LT; break;
+		case ARM_CC_GT: cc = R_ANAL_COND_GT; break;
+		case ARM_CC_LE: cc = R_ANAL_COND_LE; break;
+		}
+	}
+	return cc;
+}
+
+static void anop64(csh handle, RAnalOp *op, cs_insn *insn) {
+	ut64 addr = op->addr;
+
+	/* grab family */
+	if (cs_insn_group (handle, insn, ARM64_GRP_CRYPTO)) {
+		op->family = R_ANAL_OP_FAMILY_CRYPTO;
+	} else if (cs_insn_group (handle, insn, ARM64_GRP_CRC)) {
+		op->family = R_ANAL_OP_FAMILY_CRYPTO;
+#if CS_API_MAJOR >= 4
+	} else if (cs_insn_group (handle, insn, ARM64_GRP_PRIVILEGE)) {
+		op->family = R_ANAL_OP_FAMILY_PRIV;
+#endif
+	} else if (cs_insn_group (handle, insn, ARM64_GRP_NEON)) {
+		op->family = R_ANAL_OP_FAMILY_VEC;
+	} else if (cs_insn_group (handle, insn, ARM64_GRP_FPARMV8)) {
+		op->family = R_ANAL_OP_FAMILY_FPU;
+	} else {
+		op->family = R_ANAL_OP_FAMILY_CPU;
+	}
+
+	op->cond = cond_cs2r2 (insn->detail->arm64.cc);
+	if (op->cond == R_ANAL_COND_NV) {
+		op->type = R_ANAL_OP_TYPE_NOP;
+		return;
+	}
+
+	switch (insn->detail->arm64.cc) {
+	case ARM64_CC_GE:
+	case ARM64_CC_GT:
+	case ARM64_CC_LE:
+	case ARM64_CC_LT:
+		op->sign = true;
+		break;
+	default:
+		break;
+	}
+
+	switch (insn->id) {
+#if CS_API_MAJOR > 4
+	case ARM64_INS_UDF:
+		op->type = R_ANAL_OP_TYPE_ILL;
+		break;
+	case ARM64_INS_PACDA:
+	case ARM64_INS_PACDB:
+	case ARM64_INS_PACDZA:
+	case ARM64_INS_PACDZB:
+	case ARM64_INS_PACGA:
+	case ARM64_INS_PACIA:
+	case ARM64_INS_PACIA1716:
+	case ARM64_INS_PACIASP:
+	case ARM64_INS_PACIAZ:
+	case ARM64_INS_PACIB:
+	case ARM64_INS_PACIB1716:
+	case ARM64_INS_PACIBSP:
+	case ARM64_INS_PACIBZ:
+	case ARM64_INS_PACIZA:
+	case ARM64_INS_PACIZB:
+	case ARM64_INS_AUTDA:
+	case ARM64_INS_AUTDB:
+	case ARM64_INS_AUTDZA:
+	case ARM64_INS_AUTDZB:
+	case ARM64_INS_AUTIA:
+	case ARM64_INS_AUTIA1716:
+	case ARM64_INS_AUTIASP:
+	case ARM64_INS_AUTIAZ:
+	case ARM64_INS_AUTIB:
+	case ARM64_INS_AUTIB1716:
+	case ARM64_INS_AUTIBSP:
+	case ARM64_INS_AUTIBZ:
+	case ARM64_INS_AUTIZA:
+	case ARM64_INS_AUTIZB:
+	case ARM64_INS_XPACD:
+	case ARM64_INS_XPACI:
+	case ARM64_INS_XPACLRI:
+		op->type = R_ANAL_OP_TYPE_CMP;
+		op->family = R_ANAL_OP_FAMILY_SECURITY;
+		break;
+#endif
+	case ARM64_INS_SVC:
+		op->type = R_ANAL_OP_TYPE_SWI;
+		op->val = IMM64(0);
+		break;
+	case ARM64_INS_ADRP:
+	case ARM64_INS_ADR:
+		op->type = R_ANAL_OP_TYPE_LEA;
+		op->ptr = IMM64(1);
+		break;
+	case ARM64_INS_NOP:
+		op->type = R_ANAL_OP_TYPE_NOP;
+		op->cycles = 1;
+		break;
+	case ARM64_INS_SUB:
+		if (ISREG64(0) && REGID64(0) == ARM64_REG_SP) {
+			op->stackop = R_ANAL_STACK_INC;
+			if (ISIMM64(1)) {
+				//sub sp, 0x54
+				op->stackptr = IMM(1);
+			} else if (ISIMM64(2) && ISREG64(1) && REGID64(1) == ARM64_REG_SP) {
+				//sub sp, sp, 0x10
+				op->stackptr = IMM64(2);
+			}
+			op->val = op->stackptr;
+		} else {
+			op->stackop = R_ANAL_STACK_RESET;
+			op->stackptr = 0;
+		}
+		op->cycles = 1;
+		/* fallthru */
+	case ARM64_INS_MSUB:
+		op->type = R_ANAL_OP_TYPE_SUB;
+		break;
+	case ARM64_INS_FDIV:
+	case ARM64_INS_SDIV:
+	case ARM64_INS_UDIV:
+		op->cycles = 4;
+		op->type = R_ANAL_OP_TYPE_DIV;
+		break;
+	case ARM64_INS_MUL:
+	case ARM64_INS_SMULL:
+	case ARM64_INS_FMUL:
+	case ARM64_INS_UMULL:
+		/* TODO: if next instruction is also a MUL, cycles are /=2 */
+		/* also known as Register Indexing Addressing */
+		op->cycles = 4;
+		op->type = R_ANAL_OP_TYPE_MUL;
+		break;
+#if CS_API_MAJOR > 4
+	case ARM64_INS_ADDG:
+#endif
+	case ARM64_INS_ADD:
+		if (ISREG64 (0) && REGID64 (0) == ARM64_REG_SP) {
+			op->stackop = R_ANAL_STACK_INC;
+			if (ISIMM64 (1)) {
+				//add sp, 0x54
+				op->stackptr = -(st64)IMM (1);
+			} else if (ISIMM64 (2) && ISREG64 (1) && REGID64 (1) == ARM64_REG_SP) {
+				//add sp, sp, 0x10
+				op->stackptr = -(st64)IMM64 (2);
+			}
+			op->val = op->stackptr;
+		} else if (REGID64 (0) == ARM64_REG_SP) {
+			op->stackop = R_ANAL_STACK_RESET;
+			op->stackptr = 0;
+		}
+		op->cycles = 1;
+		op->type = R_ANAL_OP_TYPE_ADD;
+		break;
+	case ARM64_INS_ADC:
+	//case ARM64_INS_ADCS:
+	case ARM64_INS_UMADDL:
+	case ARM64_INS_SMADDL:
+	case ARM64_INS_FMADD:
+	case ARM64_INS_MADD:
+		op->type = R_ANAL_OP_TYPE_ADD;
+		break;
+	case ARM64_INS_CSEL:
+	case ARM64_INS_FCSEL:
+	case ARM64_INS_CSET:
+	case ARM64_INS_CINC:
+		op->type = R_ANAL_OP_TYPE_CMOV;
+		break;
+#if 0
+	case ARM64_INS_BTI:
+		op->type = R_ANAL_OP_TYPE_NOP;
+		op->family = R_ANAL_OP_FAMILY_SECURITY;
+		break;
+#endif
+	case ARM64_INS_MOV:
+		if (REGID64(0) == ARM64_REG_SP) {
+			op->stackop = R_ANAL_STACK_RESET;
+			op->stackptr = 0;
+		}
+		op->cycles = 1;
+		/* fallthru */
+	case ARM64_INS_MOVI:
+	case ARM64_INS_MOVK:
+	case ARM64_INS_MOVN:
+	case ARM64_INS_SMOV:
+	case ARM64_INS_UMOV:
+	case ARM64_INS_FMOV:
+	case ARM64_INS_SBFX:
+	case ARM64_INS_UBFX:
+	case ARM64_INS_UBFM:
+	case ARM64_INS_BFI:
+	case ARM64_INS_SBFIZ:
+	case ARM64_INS_UBFIZ:
+	case ARM64_INS_BIC:
+	case ARM64_INS_BFXIL:
+		op->type = R_ANAL_OP_TYPE_MOV;
+		if (ISIMM64 (1)) {
+			op->val = IMM64(1);
+		}
+		break;
+	case ARM64_INS_MRS:
+	case ARM64_INS_MSR:
+		op->type = R_ANAL_OP_TYPE_MOV;
+		op->family = R_ANAL_OP_FAMILY_PRIV;
+		break;
+	case ARM64_INS_MOVZ:
+		op->type = R_ANAL_OP_TYPE_MOV;
+		op->ptr = 0LL;
+		op->ptrsize = 8;
+		op->val = IMM64(1);
+		break;
+	case ARM64_INS_UXTB:
+	case ARM64_INS_SXTB:
+		op->type = R_ANAL_OP_TYPE_CAST;
+		op->ptr = 0LL;
+		op->ptrsize = 1;
+		break;
+	case ARM64_INS_UXTH:
+	case ARM64_INS_SXTH:
+		op->type = R_ANAL_OP_TYPE_MOV;
+		op->ptr = 0LL;
+		op->ptrsize = 2;
+		break;
+	case ARM64_INS_UXTW:
+	case ARM64_INS_SXTW:
+		op->type = R_ANAL_OP_TYPE_MOV;
+		op->ptr = 0LL;
+		op->ptrsize = 4;
+		break;
+	case ARM64_INS_BRK:
+	case ARM64_INS_HLT:
+		op->type = R_ANAL_OP_TYPE_TRAP;
+		// hlt stops the process, not skips some cycles like in x86
+		break;
+	case ARM64_INS_DMB:
+	case ARM64_INS_DSB:
+	case ARM64_INS_ISB:
+		op->family = R_ANAL_OP_FAMILY_THREAD;
+		// intentional fallthrough
+	case ARM64_INS_IC: // instruction cache invalidate
+	case ARM64_INS_DC: // data cache invalidate
+		op->type = R_ANAL_OP_TYPE_SYNC; // or cache
+		break;
+	//  XXX unimplemented instructions
+	case ARM64_INS_DUP:
+	case ARM64_INS_XTN:
+	case ARM64_INS_XTN2:
+	case ARM64_INS_REV64:
+	case ARM64_INS_EXT:
+	case ARM64_INS_INS:
+		op->type = R_ANAL_OP_TYPE_MOV;
+		break;
+	case ARM64_INS_LSL:
+		op->cycles = 1;
+		/* fallthru */
+	case ARM64_INS_SHL:
+	case ARM64_INS_USHLL:
+		op->type = R_ANAL_OP_TYPE_SHL;
+		break;
+	case ARM64_INS_LSR:
+		op->cycles = 1;
+		op->type = R_ANAL_OP_TYPE_SHR;
+		break;
+	case ARM64_INS_ASR:
+		op->cycles = 1;
+		op->type = R_ANAL_OP_TYPE_SAR;
+		break;
+	case ARM64_INS_NEG:
+#if CS_API_MAJOR > 3
+	case ARM64_INS_NEGS:
+#endif
+		op->type = R_ANAL_OP_TYPE_NOT;
+		break;
+	case ARM64_INS_FCMP:
+	case ARM64_INS_CCMP:
+	case ARM64_INS_CCMN:
+	case ARM64_INS_CMP:
+	case ARM64_INS_CMN:
+	case ARM64_INS_TST:
+		op->type = R_ANAL_OP_TYPE_CMP;
+		break;
+	case ARM64_INS_ROR:
+		op->cycles = 1;
+		op->type = R_ANAL_OP_TYPE_ROR;
+		break;
+	case ARM64_INS_AND:
+		op->type = R_ANAL_OP_TYPE_AND;
+		break;
+	case ARM64_INS_ORR:
+	case ARM64_INS_ORN:
+		op->type = R_ANAL_OP_TYPE_OR;
+		break;
+	case ARM64_INS_EOR:
+	case ARM64_INS_EON:
+		op->type = R_ANAL_OP_TYPE_XOR;
+		break;
+	case ARM64_INS_STRB:
+	case ARM64_INS_STURB:
+	case ARM64_INS_STUR:
+	case ARM64_INS_STR:
+	case ARM64_INS_STP:
+	case ARM64_INS_STNP:
+	case ARM64_INS_STXR:
+	case ARM64_INS_STXRH:
+	case ARM64_INS_STLXR:
+	case ARM64_INS_STLXRH:
+	case ARM64_INS_STXRB:
+		op->type = R_ANAL_OP_TYPE_STORE;
+		if (ISPREINDEX64 () && REGBASE64 (2) == ARM64_REG_SP) {
+			op->stackop = R_ANAL_STACK_INC;
+			op->stackptr = -(st64)MEMDISP64 (2);
+		} else if (ISPOSTINDEX64 () && REGID64 (2) == ARM64_REG_SP) {
+			op->stackop = R_ANAL_STACK_INC;
+			op->stackptr = -(st64)IMM64 (3);
+		} else if (ISPREINDEX64 () && REGBASE64 (1) == ARM64_REG_SP) {
+			op->stackop = R_ANAL_STACK_INC;
+			op->stackptr = -(st64)MEMDISP64 (1);
+		} else if (ISPOSTINDEX64 () && REGID64 (1) == ARM64_REG_SP) {
+			op->stackop = R_ANAL_STACK_INC;
+			op->stackptr = -(st64)IMM64 (2);
+		}
+		break;
+	case ARM64_INS_LDUR:
+	case ARM64_INS_LDURB:
+	case ARM64_INS_LDRSW:
+	case ARM64_INS_LDRSB:
+	case ARM64_INS_LDRSH:
+	case ARM64_INS_LDR:
+	case ARM64_INS_LDURSW:
+	case ARM64_INS_LDP:
+	case ARM64_INS_LDNP:
+	case ARM64_INS_LDPSW:
+	case ARM64_INS_LDRH:
+	case ARM64_INS_LDRB:
+		if (ISPREINDEX64 () && REGBASE64 (2) == ARM64_REG_SP) {
+			op->stackop = R_ANAL_STACK_INC;
+			op->stackptr = -(st64)MEMDISP64 (2);
+		} else if (ISPOSTINDEX64 () && REGID64 (2) == ARM64_REG_SP) {
+			op->stackop = R_ANAL_STACK_INC;
+			op->stackptr = -(st64)IMM64 (3);
+		} else if (ISPREINDEX64 () && REGBASE64 (1) == ARM64_REG_SP) {
+			op->stackop = R_ANAL_STACK_INC;
+			op->stackptr = -(st64)MEMDISP64 (1);
+		} else if (ISPOSTINDEX64 () && REGID64 (1) == ARM64_REG_SP) {
+			op->stackop = R_ANAL_STACK_INC;
+			op->stackptr = -(st64)IMM64 (2);
+		}
+		if (REGID(0) == ARM_REG_PC) {
+			op->type = R_ANAL_OP_TYPE_MJMP;
+			if (insn->detail->arm.cc != ARM_CC_AL) {
+				op->type = R_ANAL_OP_TYPE_MCJMP;
+			}
+		} else {
+			op->type = R_ANAL_OP_TYPE_LOAD;
+		}
+		switch (insn->id) {
+		case ARM64_INS_LDPSW:
+		case ARM64_INS_LDRSW:
+		case ARM64_INS_LDRSH:
+		case ARM64_INS_LDRSB:
+			op->sign = true;
+			break;
+		}
+		if (REGBASE64(1) == ARM64_REG_X29) {
+			op->stackop = R_ANAL_STACK_GET;
+			op->stackptr = 0;
+			op->ptr = MEMDISP64(1);
+		} else {
+			if (ISIMM64(1)) {
+				op->type = R_ANAL_OP_TYPE_LEA;
+				op->ptr = IMM64(1);
+				op->refptr = 8;
+			} else {
+				int d = (int)MEMDISP64(1);
+				op->ptr = (d < 0)? -d: d;
+				op->refptr = 4;
+			}
+		}
+		break;
+#if CS_API_MAJOR > 4
+	case ARM64_INS_IRG:
+		op->family = R_ANAL_OP_FAMILY_SECURITY;
+		op->type = R_ANAL_OP_TYPE_MOV;
+		break;
+	case ARM64_INS_BLRAA:
+	case ARM64_INS_BLRAAZ:
+	case ARM64_INS_BLRAB:
+	case ARM64_INS_BLRABZ:
+		op->family = R_ANAL_OP_FAMILY_SECURITY;
+		op->type = R_ANAL_OP_TYPE_RCALL;
+		break;
+	case ARM64_INS_BRAA:
+	case ARM64_INS_BRAAZ:
+	case ARM64_INS_BRAB:
+	case ARM64_INS_BRABZ:
+		op->family = R_ANAL_OP_FAMILY_SECURITY;
+		op->type = R_ANAL_OP_TYPE_RJMP;
+		break;
+	case ARM64_INS_LDRAA:
+	case ARM64_INS_LDRAB:
+		op->family = R_ANAL_OP_FAMILY_SECURITY;
+		op->type = R_ANAL_OP_TYPE_LOAD;
+		break;
+	case ARM64_INS_RETAA:
+	case ARM64_INS_RETAB:
+	case ARM64_INS_ERETAA:
+	case ARM64_INS_ERETAB:
+		op->family = R_ANAL_OP_FAMILY_SECURITY;
+		op->type = R_ANAL_OP_TYPE_RET;
+		break;
+#endif
+	case ARM64_INS_ERET:
+		op->family = R_ANAL_OP_FAMILY_PRIV;
+		op->type = R_ANAL_OP_TYPE_RET;
+		break;
+	case ARM64_INS_RET:
+		op->type = R_ANAL_OP_TYPE_RET;
+		break;
+	case ARM64_INS_BL: // bl 0x89480
+		op->type = R_ANAL_OP_TYPE_CALL;
+		op->jump = IMM64(0);
+		op->fail = addr + 4;
+		break;
+	case ARM64_INS_BLR: // blr x0
+		op->type = R_ANAL_OP_TYPE_RCALL;
+		op->fail = addr + 4;
+		//op->jump = IMM64(0);
+		break;
+	case ARM64_INS_CBZ:
+	case ARM64_INS_CBNZ:
+		op->type = R_ANAL_OP_TYPE_CJMP;
+		op->jump = IMM64(1);
+		op->fail = addr+op->size;
+		break;
+	case ARM64_INS_TBZ:
+	case ARM64_INS_TBNZ:
+		op->type = R_ANAL_OP_TYPE_CJMP;
+		op->jump = IMM64(2);
+		op->fail = addr+op->size;
+		break;
+	case ARM64_INS_BR:
+		// op->type = R_ANAL_OP_TYPE_UJMP; // RJMP ?
+		op->type = R_ANAL_OP_TYPE_RJMP;
+		op->eob = true;
+		break;
+	case ARM64_INS_B:
+		// BX LR == RET
+		if (insn->detail->arm64.operands[0].reg == ARM64_REG_LR) {
+			op->type = R_ANAL_OP_TYPE_RET;
+		} else if (insn->detail->arm64.cc) {
+			op->type = R_ANAL_OP_TYPE_CJMP;
+			op->jump = IMM64(0);
+			op->fail = addr + op->size;
+		} else {
+			op->type = R_ANAL_OP_TYPE_JMP;
+			op->jump = IMM64(0);
+		}
+		break;
+	default:
+		R_LOG_DEBUG ("ARM64 analysis: Op type %d at 0x%" PFMT64x " not handled", insn->id, op->addr);
+		break;
+	}
+}
+
+static void anal_itblock(RArchSession *as, cs_insn *insn) {
+	size_t i, size =  r_str_nlen (insn->mnemonic, 5);
+	HtUU *ht_itblock = ht_itblock_for_session (as);
+	HtUU *ht_it = ht_it_for_session (as);
+	ht_uu_update (ht_itblock, insn->address,  size);
+	for (i = 1; i < size; i++) {
+		switch (insn->mnemonic[i]) {
+		case 0x74: //'t'
+			ht_uu_update (ht_it, insn->address + (i * insn->size), insn->detail->arm.cc);
+			break;
+		case 0x65: //'e'
+			ht_uu_update (ht_it, insn->address + (i * insn->size), (insn->detail->arm.cc % 2)?
+				insn->detail->arm.cc + 1: insn->detail->arm.cc - 1);
+			break;
+		default:
+			break;
+		}
+	}
+}
+
+static void check_itblock(RArchSession *as, cs_insn *insn) {
+	HtUU *ht_itblock = ht_itblock_for_session (as);
+	HtUU *ht_it = ht_it_for_session (as);
+	bool found;
+	ut64 itlen = ht_uu_find (ht_itblock, insn->address, &found);
+	if (found) {
+		size_t x;
+		for (x = 1; x < itlen; x++) {
+			ht_uu_delete (ht_it, insn->address + (x*insn->size));
+		}
+		ht_uu_delete (ht_itblock, insn->address);
+	}
+}
