+			} else {
+				// exotic pld
+			}
+		}
+		break;
+	case ARM_INS_IT:
+		anal_itblock (as, insn);
+		op->cycles = 2;
+		break;
+	case ARM_INS_BKPT:
+		op->type = R_ANAL_OP_TYPE_TRAP;
+		op->cycles = 4;
+		break;
+	case ARM_INS_NOP:
+		op->type = R_ANAL_OP_TYPE_NOP;
+		op->cycles = 1;
+		break;
+	case ARM_INS_POP:
+		op->stackop = R_ANAL_STACK_INC;
