+	case ARM_INS_FLDMIAX:
+	case ARM_INS_LDMDA:
+	case ARM_INS_LDMDB:
+	case ARM_INS_LDMIB:
+	case ARM_INS_LDM:
+		op->type = R_ANAL_OP_TYPE_POP;
