+		op->val = IMM(0);
+		break;
+	case ARM_INS_ROR:
+	case ARM_INS_RRX:
+		op->cycles = 1;
+		op->type = R_ANAL_OP_TYPE_ROR;
+		break;
+	case ARM_INS_AND:
+		op->type = R_ANAL_OP_TYPE_AND;
+		break;
+	case ARM_INS_ORR:
+	case ARM_INS_ORN:
+		op->type = R_ANAL_OP_TYPE_OR;
+		break;
+	case ARM_INS_EOR:
+		op->type = R_ANAL_OP_TYPE_XOR;
+		break;
+	case ARM_INS_CMP:
+	case ARM_INS_CMN:
