+		op->cycles = 4;
+		op->type = R_ANAL_OP_TYPE_CALL;
+		op->jump = IMM(0) & UT32_MAX;
+		op->fail = addr + op->size;
+		op->hint.new_bits = as->config->bits;
+		break;
+	case ARM_INS_CBZ:
+	case ARM_INS_CBNZ:
+		op->cycles = 4;
+		op->type = R_ANAL_OP_TYPE_CJMP;
+		op->jump = IMM (1) & UT32_MAX;
+		op->fail = addr + op->size;
+		if (op->jump == op->fail) {
