+			op->type = R_ANAL_OP_TYPE_ILL;
+			op->fail = addr+op->size;
+		} else if (insn->detail->arm.cc == ARM_CC_AL) {
+			op->type = R_ANAL_OP_TYPE_JMP;
+			op->fail = UT64_MAX;
+		} else {
+			op->type = R_ANAL_OP_TYPE_CJMP;
+			op->fail = addr+op->size;
+		}
+		op->jump = IMM(0) & UT32_MAX;
+		// propagate bits to create correctly hints ranges
+		op->hint.new_bits = as->config->bits;
+		break;
+	case ARM_INS_BX:
+	case ARM_INS_BXJ:
+		/* bx reg */
+		op->cycles = 4;
+		switch (REGID(0)) {
+		case ARM_REG_LR:
+			op->type = R_ANAL_OP_TYPE_RET;
+			break;
+		case ARM_REG_IP:
+			op->type = R_ANAL_OP_TYPE_UJMP;
+			break;
+		case ARM_REG_PC:
+			// bx pc is well known without ESIL
+			op->type = R_ANAL_OP_TYPE_UJMP;
+			op->jump = (addr & ~3LL) + pcdelta;
+			op->hint.new_bits = 32;
+			break;
+		default:
+			op->type = R_ANAL_OP_TYPE_UJMP;
+			op->eob = true;
+			break;
+		}
+		break;
+	case ARM_INS_ADR:
+		op->cycles = 2;
+		op->type = R_ANAL_OP_TYPE_LEA;
+		// Set the pointer address and align it
+		op->ptr = IMM(1) + addr + 4 - (addr%4);
+		op->refptr = 1;
+		break;
+	case ARM_INS_UXTAB:
+	case ARM_INS_UXTAB16:
+		op->type = R_ANAL_OP_TYPE_ADD;
+		op->ptr = 0LL;
+		op->ptrsize = 1;
+		break;
+	case ARM_INS_UXTAH:
+		op->type = R_ANAL_OP_TYPE_ADD;
+		op->ptr = 0LL;
+		op->ptrsize = 2;
+		break;
+	case ARM_INS_UXTB:
+	case ARM_INS_UXTB16:
+		op->type = R_ANAL_OP_TYPE_CAST;
+		op->ptr = 0LL;
+		op->ptrsize = 1;
+		break;
+	case ARM_INS_UXTH:
+		op->type = R_ANAL_OP_TYPE_CAST;
+		op->ptr = 0LL;
+		op->ptrsize = 2;
+		break;
+	default:
+		R_LOG_DEBUG ("ARM analysis: Op type %d at 0x%" PFMT64x " not handled", insn->id, op->addr);
+		break;
+	}
