+	.arch = "arm",
+	.endian = R_SYS_ENDIAN_LITTLE | R_SYS_ENDIAN_BIG,
+	.bits = R_SYS_BITS_PACK3 (16, 32, 64),
+#if 0
+	// made obsolete by "e anal.mask = true"
+	.anal_mask = anal_mask,
+#endif
+	.preludes = anal_preludes,
+	.decode = decode,
+	.init = init,
+	.fini = fini,
+	.info = archinfo,
+	.regs = regs,
+	.mnemonics = arm_mnemonics,
+};
