+	case X86_INS_FBSTP:
+	case X86_INS_FCOMPP:
+	case X86_INS_FDECSTP:
+	case X86_INS_FEMMS:
+	case X86_INS_FFREE:
+	case X86_INS_FICOM:
+	case X86_INS_FICOMP:
+	case X86_INS_FINCSTP:
+	case X86_INS_FNCLEX:
+	case X86_INS_FNINIT:
+	case X86_INS_FNSTCW:
+	case X86_INS_FNSTSW:
+	case X86_INS_FPATAN:
+	case X86_INS_FPREM:
+	case X86_INS_FPREM1:
+	case X86_INS_FPTAN:
+#if CS_API_MAJOR >=4
