+	case X86_INS_FRNDINT:
+	case X86_INS_FRSTOR:
+	case X86_INS_FNSAVE:
+	case X86_INS_FSCALE:
+	case X86_INS_FSETPM:
+	case X86_INS_FSINCOS:
+	case X86_INS_FNSTENV:
+	case X86_INS_FXAM:
+	case X86_INS_FXSAVE:
+	case X86_INS_FXSAVE64:
+	case X86_INS_FXTRACT:
+	case X86_INS_FYL2X:
+	case X86_INS_FYL2XP1:
+	case X86_INS_FISTTP:
+	case X86_INS_FSQRT:
+	case X86_INS_FXCH:
+		break;
+	case X86_INS_FTST:
+	case X86_INS_FUCOMI:
+	case X86_INS_FUCOMPP:
+	case X86_INS_FUCOMP:
+	case X86_INS_FUCOM:
+		break;
+	case X86_INS_FABS:
+		break;
+	case X86_INS_FLDCW:
+	case X86_INS_FLDENV:
+	case X86_INS_FLDL2E:
+	case X86_INS_FLDL2T:
+	case X86_INS_FLDLG2:
+	case X86_INS_FLDLN2:
+	case X86_INS_FLDPI:
+	case X86_INS_FLDZ:
+	case X86_INS_FLD1:
+	case X86_INS_FLD:
