+	case X86_INS_FISUBR:
+	case X86_INS_FSUBRP:
+	case X86_INS_FSUB:
+	case X86_INS_FISUB:
+	case X86_INS_FSUBP:
+		break;
+	case X86_INS_FMUL:
+	case X86_INS_FIMUL:
+	case X86_INS_FMULP:
+		break;
