+		} else {
+			r_strbuf_append (&op->esil, "al,edi,=[1],df,?{,1,edi,-=,},df,!,?{,1,edi,+=,}");
+		}
+		break;
+	case X86_INS_STOSW:
+		if (bits < 32) {
