+				src = getarg (&gop, 1, 0, NULL, NULL);
+				dst = getarg (&gop, 0, 0, NULL, NULL);
+				esilprintf (op, "%s,%sl,=", src, dst);
+				free (src);
+				free (dst);
+			}
+		}
+		if (is_xmm_reg (INSOP (1))) {
+			if (!is_xmm_reg (INSOP (0))) {
+				src = getarg (&gop, 1, 0, NULL, NULL);
+				dst = getarg (&gop, 0, 1, NULL, NULL);
+				esilprintf (op, "%sl,%s", src, dst);
+				free (src);
+				free (dst);
+			}
+		}
