+	case X86_INS_ROL:
+	case X86_INS_RCL:
+		// TODO: RCL Still does not work as intended
+		//  - Set flags
+		{
+			src = getarg (&gop, 1, 0, NULL, NULL);
+			src2 = getarg (&gop, 0, 0, NULL, NULL);
+			dst = getarg (&gop, 0, 1, NULL, NULL);
+			esilprintf (op, "%s,%s,<<<,%s", src, src2, dst);
+			free (src);
+			free (src2);
+			free (dst);
+		}
+		break;
+	case X86_INS_ROR:
+	case X86_INS_RCR:
+		// TODO: RCR Still does not work as intended
+		//  - Set flags
+		{
+			src = getarg (&gop, 1, 0, NULL, NULL);
+			src2 = getarg (&gop, 0, 0, NULL, NULL);
+			dst = getarg (&gop, 0, 1, NULL, NULL);
+			esilprintf (op, "%s,%s,>>>,%s", src, src2, dst);
+			free (src);
+			free (src2);
+			free (dst);
+		}
+		break;
+	case X86_INS_CPUID:
+		// https://c9x.me/x86/html/file_module_x86_id_45.html
+		// GenuineIntel
+		esilprintf (op, "0xa,eax,=,0x756E6547,ebx,=,0x6C65746E,ecx,=,0x49656E69,edx,=");
+		break;
+	case X86_INS_SHLD:
+	case X86_INS_SHLX:
