+	case X86_INS_PCMPEQB:
+	case X86_INS_PCMPEQD:
+	case X86_INS_PCMPEQW:
+	case X86_INS_PCMPGTB:
+	case X86_INS_PCMPGTD:
+	case X86_INS_PCMPGTW:
+	case X86_INS_PCMPEQQ:
+	case X86_INS_PCMPESTRI:
+	case X86_INS_PCMPESTRM:
+	case X86_INS_PCMPGTQ:
+	case X86_INS_PCMPISTRI:
+	case X86_INS_PCMPISTRM:
+#if CS_API_MAJOR >= 4
+	case X86_INS_VPCMPB:
+#endif
+	case X86_INS_VPCMPD:
+	case X86_INS_VPCMPEQB:
+	case X86_INS_VPCMPEQD:
+	case X86_INS_VPCMPEQQ:
+	case X86_INS_VPCMPEQW:
+	case X86_INS_VPCMPESTRI:
+	case X86_INS_VPCMPESTRM:
+	case X86_INS_VPCMPGTB:
+	case X86_INS_VPCMPGTD:
+	case X86_INS_VPCMPGTQ:
+	case X86_INS_VPCMPGTW:
+	case X86_INS_VPCMPISTRI:
+	case X86_INS_VPCMPISTRM:
+	case X86_INS_VPCMPQ:
+#if CS_API_MAJOR >= 4
+	case X86_INS_VPCMPUB:
+#endif
+	case X86_INS_VPCMPUD:
+	case X86_INS_VPCMPUQ:
+#if CS_API_MAJOR >= 4
+	case X86_INS_VPCMPUW:
+	case X86_INS_VPCMPW:
+#endif
+		op->type = R_ANAL_OP_TYPE_CMP;
+		op->family = R_ANAL_OP_FAMILY_VEC;
+		break;
+	case X86_INS_MOVSS:
+	case X86_INS_MOV:
+	case X86_INS_MOVAPS:
+	case X86_INS_MOVAPD:
+	case X86_INS_MOVZX:
+	case X86_INS_MOVUPS:
+	case X86_INS_MOVABS:
+	case X86_INS_MOVHPD:
+	case X86_INS_MOVHPS:
+	case X86_INS_MOVLPD:
+	case X86_INS_MOVLPS:
+	case X86_INS_MOVBE:
+	case X86_INS_MOVSB:
+	case X86_INS_MOVSD:
+	case X86_INS_MOVSQ:
+	case X86_INS_MOVSX:
+	case X86_INS_MOVSXD:
+	case X86_INS_MOVSW:
+	case X86_INS_MOVD:
+	case X86_INS_MOVQ:
+	case X86_INS_MOVDQ2Q:
+		{
+		op->type = R_ANAL_OP_TYPE_MOV;
+		op0_memimmhandle (op, insn, addr, regsz);
+		op1_memimmhandle (op, insn, addr, regsz);
+		}
+		break;
+	// comiss
+	case X86_INS_COMISS:
+	case X86_INS_UCOMISS:
+	case X86_INS_VCOMISS:
+	case X86_INS_VUCOMISS:
+		op->family = R_ANAL_OP_FAMILY_SIMD;
+		break;
+	case X86_INS_ROL:
+	case X86_INS_RCL:
+		// TODO: RCL Still does not work as intended
+		//  - Set flags
+		op->type = R_ANAL_OP_TYPE_ROL;
+		break;
+	case X86_INS_ROR:
+	case X86_INS_RCR:
+		// TODO: RCR Still does not work as intended
+		//  - Set flags
+		op->type = R_ANAL_OP_TYPE_ROR;
+		break;
+	case X86_INS_SHL:
+	case X86_INS_SHLD:
+	case X86_INS_SHLX:
+		// TODO: Set CF: Carry flag is the last bit shifted out due to
+		// this operation. It is undefined for SHL and SHR where the
+		// number of bits shifted is greater than the size of the
+		// destination.
+		op->type = R_ANAL_OP_TYPE_SHL;
+		break;
+	case X86_INS_SAR:
+	case X86_INS_SARX:
+		// TODO: Set CF. See case X86_INS_SHL for more details.
+		op->type = R_ANAL_OP_TYPE_SAR;
+		break;
+	case X86_INS_SAL:
+		// TODO: Set CF: See case X86_INS_SAL for more details.
+		op->type = R_ANAL_OP_TYPE_SAL;
+		break;
+	case X86_INS_SALC:
+		op->type = R_ANAL_OP_TYPE_SAL;
+		break;
+	case X86_INS_SHR:
+	case X86_INS_SHRD:
+	case X86_INS_SHRX:
+		// TODO: Set CF: See case X86_INS_SAL for more details.
+		op->type = R_ANAL_OP_TYPE_SHR;
+		op->val = INSOP(1).imm;
+		// XXX this should be op->imm
+		//op->src[0] = r_anal_value_new ();
+		//op->src[0]->imm = INSOP(1).imm;
+		break;
+	case X86_INS_CMP:
+	case X86_INS_CMPPD:
+	case X86_INS_CMPPS:
+	case X86_INS_CMPSW:
+	case X86_INS_CMPSD:
+	case X86_INS_CMPSQ:
+	case X86_INS_CMPSB:
+	case X86_INS_CMPSS:
+		op->type = R_ANAL_OP_TYPE_CMP;
+		inscmp (op, addr, insn, regsz);
+		break;
+	case X86_INS_TEST:
+		op->type = R_ANAL_OP_TYPE_ACMP; // compare via and
+		inscmp (op, addr, insn, regsz);
+		break;
+	case X86_INS_LEA:
+		op->type = R_ANAL_OP_TYPE_LEA;
+		switch (INSOP(1).type) {
+		case X86_OP_MEM:
+			// op->type = R_ANAL_OP_TYPE_ULEA;
+			op->disp = INSOP(1).mem.disp;
+			op->refptr = INSOP(1).size;
+			switch (INSOP(1).mem.base) {
+			case X86_REG_RIP:
+				op->ptr = addr + op->size + op->disp;
+				break;
+			case X86_REG_RBP:
+			case X86_REG_EBP:
+				op->stackop = R_ANAL_STACK_GET;
+				op->stackptr = regsz;
+				break;
+			default:
+				/* unhandled */
+				break;
+			}
+			break;
+		case X86_OP_IMM:
+			if (INSOP(1).imm > 10) {
+				op->ptr = INSOP(1).imm;
+			}
+			break;
+		default:
+			break;
+		}
+		break;
+	case X86_INS_PUSHAW:
+	// pushal, popal - push/pop EAX,EBX,ECX,EDX,ESP,EBP,ESI,EDI
+	case X86_INS_PUSHAL:
+		op->ptr = UT64_MAX;
+		op->type = R_ANAL_OP_TYPE_UPUSH;
+		op->stackop = R_ANAL_STACK_INC;
+		op->stackptr = regsz * 8;
+		break;
+	case X86_INS_ENTER:
+	case X86_INS_PUSH:
+	case X86_INS_PUSHF:
+	case X86_INS_PUSHFD:
+	case X86_INS_PUSHFQ:
+		switch (INSOP(0).type) {
+		case X86_OP_MEM:
+			if (INSOP(0).mem.disp && !INSOP(0).mem.base && !INSOP(0).mem.index) {
+				op->val = op->ptr = INSOP(0).mem.disp;
+				op->type = R_ANAL_OP_TYPE_PUSH;
+			} else {
+				op->type = R_ANAL_OP_TYPE_UPUSH;
+			}
+			op->cycles = CYCLE_REG + CYCLE_MEM;
+			break;
+		case X86_OP_IMM:
+			op->val = op->ptr = INSOP(0).imm;
+			op->type = R_ANAL_OP_TYPE_PUSH;
+			op->cycles = CYCLE_REG + CYCLE_MEM;
+			break;
+		case X86_OP_REG:
+			op->type = R_ANAL_OP_TYPE_RPUSH;
+			op->cycles = CYCLE_REG + CYCLE_MEM;
+			break;
+		default:
+			op->type = R_ANAL_OP_TYPE_UPUSH;
+			op->cycles = CYCLE_MEM + CYCLE_MEM;
+			break;
+		}
+		op->stackop = R_ANAL_STACK_INC;
+		op->stackptr = regsz;
+		break;
+	case X86_INS_LEAVE:
+		op->type = R_ANAL_OP_TYPE_POP;
+		op->stackop = R_ANAL_STACK_INC;
+		op->stackptr = -regsz;
+		break;
+	case X86_INS_POP:
+	case X86_INS_POPF:
+	case X86_INS_POPFD:
+	case X86_INS_POPFQ:
+		op->type = R_ANAL_OP_TYPE_POP;
+		op->stackop = R_ANAL_STACK_INC;
+		op->stackptr = -regsz;
+		break;
+	case X86_INS_POPAW:
+	case X86_INS_POPAL:
+		op->type = R_ANAL_OP_TYPE_POP;
+		op->stackop = R_ANAL_STACK_INC;
+		op->stackptr = -regsz * 8;
+		break;
+	case X86_INS_IRET:
+	case X86_INS_IRETD:
+	case X86_INS_IRETQ:
+	case X86_INS_SYSRET:
