+		op->stackop = R_ANAL_STACK_INC;
+		op->stackptr = -regsz;
+		op->cycles = CYCLE_MEM + CYCLE_JMP;
+		break;
+#if CS_API_MAJOR >= 4
+	case X86_INS_UD0:
+#endif
+	case X86_INS_UD2:
+#if CS_API_MAJOR == 4
+	case X86_INS_UD2B:
+#endif
+	case X86_INS_INT3:
