+		break;
+	case X86_INS_VMCALL:
+	case X86_INS_VMMCALL:
+		op->type = R_ANAL_OP_TYPE_TRAP;
+		break;
+	case X86_INS_JL:
+	case X86_INS_JLE:
+	case X86_INS_JA:
+	case X86_INS_JAE:
+	case X86_INS_JB:
+	case X86_INS_JBE:
+	case X86_INS_JCXZ:
+	case X86_INS_JECXZ:
+	case X86_INS_JRCXZ:
+	case X86_INS_JO:
+	case X86_INS_JNO:
+	case X86_INS_JS:
+	case X86_INS_JNS:
+	case X86_INS_JP:
+	case X86_INS_JNP:
+	case X86_INS_JE:
+	case X86_INS_JNE:
+	case X86_INS_JG:
+	case X86_INS_JGE:
+	case X86_INS_LOOP:
+	case X86_INS_LOOPE:
+	case X86_INS_LOOPNE:
+		op->type = R_ANAL_OP_TYPE_CJMP;
+		op->jump = INSOP(0).imm;
+		op->fail = addr + op->size;
+		op->cycles = CYCLE_JMP;
+		switch (insn->id) {
+		case X86_INS_JL:
+		case X86_INS_JLE:
+		case X86_INS_JS:
+		case X86_INS_JG:
+		case X86_INS_JGE:
