+			break;
+		}
+		break;
+	case X86_INS_CALL:
+	case X86_INS_LCALL:
+		op->cycles = CYCLE_JMP + CYCLE_MEM;
+		switch (INSOP(0).type) {
+		case X86_OP_IMM:
+			op->type = R_ANAL_OP_TYPE_CALL;
+			// TODO: what if UCALL?
+			if (INSOP(1).type == X86_OP_IMM) {
+				ut64 seg = INSOP(0).imm;
+				ut64 off = INSOP(1).imm;
+				op->ptr = INSOP (0).mem.disp;
+				op->jump = (seg << a->config->seggrn) + off;
+			} else {
+				op->jump = INSOP(0).imm;
+			}
+			op->fail = addr + op->size;
+			break;
+		case X86_OP_MEM:
+			op->type = R_ANAL_OP_TYPE_UCALL;
+			op->jump = UT64_MAX;
+			op->ptr = INSOP (0).mem.disp;
+			op->disp = INSOP (0).mem.disp;
+			op->reg = NULL;
+			op->ireg = NULL;
+			op->cycles += CYCLE_MEM;
+			if (INSOP (0).mem.index == X86_REG_INVALID) {
+				if (INSOP (0).mem.base != X86_REG_INVALID) {
+					op->reg = cs_reg_name (*handle, INSOP (0).mem.base);
+					op->type = R_ANAL_OP_TYPE_IRCALL;
+				}
+			} else {
+				op->ireg = cs_reg_name (*handle, INSOP (0).mem.index);
+				op->scale = INSOP(0).mem.scale;
+			}
+			if (INSOP (0).mem.base == X86_REG_RIP) {
+				op->ptr += addr + insn->size;
+				op->refptr = 8;
+			}
+			break;
+		case X86_OP_REG:
+			op->reg = cs_reg_name (*handle, INSOP (0).reg);
+			op->type = R_ANAL_OP_TYPE_RCALL;
+			op->ptr = UT64_MAX;
+			op->cycles += CYCLE_REG;
+			break;
+		default:
+			op->type = R_ANAL_OP_TYPE_UCALL;
+			op->jump = UT64_MAX;
+			break;
+		}
+		break;
+	case X86_INS_JMP:
+	case X86_INS_LJMP:
+		// TODO: what if UJMP?
+		switch (INSOP(0).type) {
+		case X86_OP_IMM:
+			if (INSOP(1).type == X86_OP_IMM) {
+				ut64 seg = INSOP(0).imm;
+				ut64 off = INSOP(1).imm;
+				op->ptr = INSOP (0).mem.disp;
+				op->jump = (seg << a->config->seggrn) + off;
+			} else {
+				op->jump = INSOP(0).imm;
+			}
+			op->type = R_ANAL_OP_TYPE_JMP;
+			op->cycles = CYCLE_JMP;
+			break;
+		case X86_OP_MEM:
+			// op->type = R_ANAL_OP_TYPE_UJMP;
+			op->type = R_ANAL_OP_TYPE_MJMP;
+			op->ptr = INSOP (0).mem.disp;
+			op->disp = INSOP (0).mem.disp;
+			op->reg = NULL;
+			op->ireg = NULL;
+			op->cycles = CYCLE_JMP + CYCLE_MEM;
+			if (INSOP(0).mem.base != X86_REG_INVALID) {
+				if (INSOP (0).mem.base != X86_REG_INVALID) {
+					op->reg = cs_reg_name (*handle, INSOP (0).mem.base);
+					op->type = R_ANAL_OP_TYPE_IRJMP;
+				}
+			}
+			if (INSOP (0).mem.index == X86_REG_INVALID) {
+				op->ireg = NULL;
+			} else {
+				op->type = R_ANAL_OP_TYPE_UJMP;
+				op->ireg = cs_reg_name (*handle, INSOP (0).mem.index);
+				op->scale = INSOP (0).mem.scale;
+			}
+			if (INSOP(0).mem.base == X86_REG_RIP) {
+				op->ptr += addr + insn->size;
+				op->refptr = 8;
+			}
+			break;
+		case X86_OP_REG:
+			{
+			op->cycles = CYCLE_JMP + CYCLE_REG;
+			op->reg = cs_reg_name (gop.handle, INSOP(0).reg);
+			op->type = R_ANAL_OP_TYPE_RJMP;
+			op->ptr = UT64_MAX;
+			}
+			break;
+		//case X86_OP_FP:
+		default: // other?
+			op->type = R_ANAL_OP_TYPE_UJMP;
+			op->ptr = UT64_MAX;
+			break;
+		}
+		break;
+	case X86_INS_IN:
+	case X86_INS_INSW:
+	case X86_INS_INSD:
+	case X86_INS_INSB:
+		op->type = R_ANAL_OP_TYPE_IO;
+		op->type2 = 0;
+		break;
+	case X86_INS_OUT:
+	case X86_INS_OUTSB:
+	case X86_INS_OUTSD:
+	case X86_INS_OUTSW:
+		op->type = R_ANAL_OP_TYPE_IO;
+		op->type2 = 1;
+		break;
+	case X86_INS_VXORPD:
+	case X86_INS_VXORPS:
+	case X86_INS_VPXORD:
+	case X86_INS_VPXORQ:
+	case X86_INS_VPXOR:
+	case X86_INS_XORPS:
+	case X86_INS_KXORW:
+	case X86_INS_PXOR:
+		op->type = R_ANAL_OP_TYPE_XOR;
+		if (INSOP(0).type == X86_OP_MEM) {
+			op->direction = R_ANAL_OP_DIR_WRITE;
+		} else if (INSOP(1).type == X86_OP_MEM) {
+			op->direction = R_ANAL_OP_DIR_READ;
+		}
+		break;
+	case X86_INS_XOR:
+		op->type = R_ANAL_OP_TYPE_XOR;
+		if (INSOP(0).type == X86_OP_MEM) {
+			op->direction = R_ANAL_OP_DIR_WRITE;
+		} else if (INSOP(1).type == X86_OP_MEM) {
+			op->direction = R_ANAL_OP_DIR_READ;
+		}
+		// TODO: Add stack indexing handling chang
+		op0_memimmhandle (op, insn, addr, regsz);
+		op1_memimmhandle (op, insn, addr, regsz);
+		break;
+	case X86_INS_OR:
+		// The OF and CF flags are cleared; the SF, ZF, and PF flags are
+		// set according to the result. The state of the AF flag is
+		// undefined.
+		op->type = R_ANAL_OP_TYPE_OR;
+		// TODO: Add stack indexing handling chang
+		op0_memimmhandle (op, insn, addr, regsz);
+		op1_memimmhandle (op, insn, addr, regsz);
+		break;
+	case X86_INS_INC:
+		// The CF flag is not affected. The OF, SF, ZF, AF, and PF flags
+		// are set according to the result.
+		op->type = R_ANAL_OP_TYPE_ADD;
+		op->val = 1;
+		break;
+	case X86_INS_DEC:
+		// The CF flag is not affected. The OF, SF, ZF, AF, and PF flags
+		// are set according to the result.
+		op->type = R_ANAL_OP_TYPE_SUB;
+		op->val = 1;
+		break;
+	case X86_INS_NEG:
+		op->type = R_ANAL_OP_TYPE_SUB;
+		op->family = R_ANAL_OP_FAMILY_CPU;
+		break;
+	case X86_INS_NOT:
+		op->type = R_ANAL_OP_TYPE_NOT;
+		op->family = R_ANAL_OP_FAMILY_CPU;
+		break;
+	case X86_INS_PSUBB:
+	case X86_INS_PSUBW:
+	case X86_INS_PSUBD:
+	case X86_INS_PSUBQ:
+	case X86_INS_PSUBSB:
+	case X86_INS_PSUBSW:
+	case X86_INS_PSUBUSB:
+	case X86_INS_PSUBUSW:
+		op->type = R_ANAL_OP_TYPE_SUB;
+		break;
+	case X86_INS_SUB:
+		op->type = R_ANAL_OP_TYPE_SUB;
+		op_stackidx (op, insn, false);
+		op0_memimmhandle (op, insn, addr, regsz);
+		op1_memimmhandle (op, insn, addr, regsz);
+		break;
+	case X86_INS_SBB:
+		// dst = dst - (src + cf)
+		op->type = R_ANAL_OP_TYPE_SUB;
+		break;
+	case X86_INS_LIDT:
+		op->type = R_ANAL_OP_TYPE_LOAD;
+		op->family = R_ANAL_OP_FAMILY_PRIV;
+		break;
+	case X86_INS_SIDT:
+		op->type = R_ANAL_OP_TYPE_STORE;
+		op->family = R_ANAL_OP_FAMILY_PRIV;
+		break;
+	case X86_INS_RDRAND:
+	case X86_INS_RDSEED:
+	case X86_INS_RDMSR:
+	case X86_INS_RDPMC:
+	case X86_INS_RDTSC:
+	case X86_INS_RDTSCP:
+	case X86_INS_CRC32:
+	case X86_INS_SHA1MSG1:
+	case X86_INS_SHA1MSG2:
+	case X86_INS_SHA1NEXTE:
+	case X86_INS_SHA1RNDS4:
+	case X86_INS_SHA256MSG1:
+	case X86_INS_SHA256MSG2:
+	case X86_INS_SHA256RNDS2:
+	case X86_INS_AESDECLAST:
+	case X86_INS_AESDEC:
+	case X86_INS_AESENCLAST:
+	case X86_INS_AESENC:
+	case X86_INS_AESIMC:
+	case X86_INS_AESKEYGENASSIST:
+		// AES instructions
+		op->family = R_ANAL_OP_FAMILY_CRYPTO;
+		op->type = R_ANAL_OP_TYPE_MOV; // XXX
+		break;
+	case X86_INS_ANDN:
+	case X86_INS_ANDPD:
+	case X86_INS_ANDPS:
+	case X86_INS_ANDNPD:
+	case X86_INS_ANDNPS:
+		op->type = R_ANAL_OP_TYPE_AND;
+		break;
+	case X86_INS_AND:
+		op->type = R_ANAL_OP_TYPE_AND;
+		// TODO: Add stack register change operation
+		op0_memimmhandle (op, insn, addr, regsz);
+		op1_memimmhandle (op, insn, addr, regsz);
+		break;
+	case X86_INS_IDIV:
+		op->type = R_ANAL_OP_TYPE_DIV;
+		break;
+	case X86_INS_DIV:
+		op->type = R_ANAL_OP_TYPE_DIV;
+		break;
+	case X86_INS_IMUL:
+		op->type = R_ANAL_OP_TYPE_MUL;
+		op->sign = true;
+		break;
+	case X86_INS_AAM:
+	case X86_INS_MUL:
+	case X86_INS_MULX:
+	case X86_INS_MULPD:
+	case X86_INS_MULPS:
+	case X86_INS_MULSD:
+	case X86_INS_MULSS:
+		op->type = R_ANAL_OP_TYPE_MUL;
+		break;
+	case X86_INS_PACKSSDW:
+	case X86_INS_PACKSSWB:
+	case X86_INS_PACKUSWB:
+		op->type = R_ANAL_OP_TYPE_MOV;
+		op->family = R_ANAL_OP_FAMILY_VEC;
+		break;
+	case X86_INS_PADDB:
+	case X86_INS_PADDD:
+	case X86_INS_PADDW:
+	case X86_INS_PADDSB:
+	case X86_INS_PADDSW:
+	case X86_INS_PADDUSB:
+	case X86_INS_PADDUSW:
+		op->type = R_ANAL_OP_TYPE_ADD;
+		op->family = R_ANAL_OP_FAMILY_VEC;
+		break;
+	case X86_INS_XCHG:
+		op->type = R_ANAL_OP_TYPE_MOV;
+		op->family = R_ANAL_OP_FAMILY_CPU;
+		break;
+	case X86_INS_XADD: /* xchg + add */
+		op->type = R_ANAL_OP_TYPE_ADD;
+		op->family = R_ANAL_OP_FAMILY_CPU;
+		break;
+	case X86_INS_FADD:
+#if CS_API_MAJOR == 4
+	case X86_INS_FADDP:
+#endif
+		op->family = R_ANAL_OP_FAMILY_FPU;
+		op->type = R_ANAL_OP_TYPE_ADD;
+		break;
+	case X86_INS_ADDPS:
+	case X86_INS_ADDSD:
+	case X86_INS_ADDSS:
+	case X86_INS_ADDSUBPD:
+	case X86_INS_ADDSUBPS:
+	case X86_INS_ADDPD:
+		// The OF, SF, ZF, AF, CF, and PF flags are set according to the
+		// result.
+		op->type = R_ANAL_OP_TYPE_ADD;
+		op_stackidx (op, insn, true);
+		op->val = INSOP(1).imm;
+		break;
+	case X86_INS_ADD:
+		// The OF, SF, ZF, AF, CF, and PF flags are set according to the
+		// result.
+		op->type = R_ANAL_OP_TYPE_ADD;
+		op_stackidx (op, insn, true);
+		op0_memimmhandle (op, insn, addr, regsz);
+		op1_memimmhandle (op, insn, addr, regsz);
+		break;
+	case X86_INS_ADC:
+		op->type = R_ANAL_OP_TYPE_ADD;
+		break;
+		/* Direction flag */
+	case X86_INS_CLD:
+		op->type = R_ANAL_OP_TYPE_MOV;
+		break;
+	case X86_INS_STD:
+		op->type = R_ANAL_OP_TYPE_MOV;
+		break;
+	case X86_INS_SUBSD:    //cvtss2sd
+	case X86_INS_CVTSS2SD: //cvtss2sd
+		break;
+	}
+	if (cs_insn_group (*handle, insn, X86_GRP_MMX)) {
+		op->family = R_ANAL_OP_FAMILY_VEC;
+	}
+	// TODO: add SSE* families?
+	if (cs_insn_group (*handle, insn, X86_GRP_SSE1)) {
+		op->family = R_ANAL_OP_FAMILY_VEC;
+	}
+	if (cs_insn_group (*handle, insn, X86_GRP_SSE2)) {
+		op->family = R_ANAL_OP_FAMILY_VEC;
+	}
+	if (cs_insn_group (*handle, insn, X86_GRP_SSE3)) {
+		op->family = R_ANAL_OP_FAMILY_VEC;
+	}
+}
