+static int replace(int argc, const char *argv[], char *newstr) {
+#define MAXPSEUDOOPS 10
+	int i, j, k, d;
+	char ch;
+	struct {
+		int narg;
+		const char *op;
+		const char *str;
+		int args[MAXPSEUDOOPS];
+	} ops[] = {
+		{ 0, "add", "# = # + #", { 1, 2, 3 } },
+		{ 0, "addi", "# = # + #", { 1, 2, 3 } },
+		{ 0, "and", "# = # & #", { 1, 2, 3 } },
+		{ 0, "andi", "# = # & #", { 1, 2, 3 } },
+		{ 0, "beq", "if (# == #) goto #", { 1, 2, 3 } },
+		{ 0, "auipc", "# = pc + #", {1, 2} },
+		{ 0, "bleu", "if (unsigned)# <= # goto #", { 1, 2, 3 } },
+		{ 0, "bltu", "if (unsigned)# < # goto #", { 1, 2, 3 } },
+		{ 0, "blt", "if (# < #) goto #", { 1, 2, 3 } },
+		{ 0, "beqz", "if (# == 0) goto #", { 1, 2 } },
+		{ 0, "bne", "if (# != #) goto #", { 1, 2, 3 } },
+		{ 0, "bnez", "if (# != 0) goto #", { 1, 2 } },
+		{ 0, "bgez", "if (# >= 0) goto #", { 1, 2 } },
+		{ 0, "bgtz", "if (# > 0) goto #", { 1, 2 } },
+		{ 0, "fld", "# = #", { 1, 2 } },
+		{ 0, "j", "jmp #", { 1 } },
+		{ 0, "jr", "jmp #", { 1 } },
+		{ 0, "jalr", "jmp #", { 1 } },
+		{ 0, "jal", "jmp #", { 1 } },
+		{ 0, "ld", "# = (double)[#]", { 1, 2 } },
+		{ 0, "li", "# = #", { 1, 2 } },
+		{ 0, "lh", "# = [#]", { 1, 2 } },
+		{ 0, "lui", "# = #", { 1, 2 } },
+		{ 0, "lbu", "# = (unsigned)[#]", { 1, 2 } },
+		{ 0, "lhu", "# = (unsigned)[#]", { 1, 2 } },
+		{ 0, "lw", "# = [#]", { 1, 2 } },
+		{ 0, "mv", "# = #", { 1, 2 } },
+		{ 0, "or", "# = # | #", { 1, 2, 3 } },
+		{ 0, "sd", "[#] = (double)#", { 2, 1 } },
+		{ 0, "sw", "[#] = #", { 2, 1 } },
+		{ 0, "sb", "[#] = #", { 2, 1 } },
+		{ 0, "sh", "[#] = #", { 2, 1 } },
+		{ 0, "sub", "# = # - #", { 1, 2, 3 } },
+		{ 0, NULL }
+	};
+	if (!newstr) {
+		return false;
+	}
+
+	for (i = 0; ops[i].op; i++) {
+		if (ops[i].narg) {
+			if (argc - 1 != ops[i].narg) {
+				continue;
+			}
+		}
+		if (!strcmp (ops[i].op, argv[0])) {
+			if (newstr) {
+				d = 0;
+				j = 0;
