+static int parse(RParse *p, const char *data, char *str) {
+	char w0[256], w1[256], w2[256], w3[256];
+	int i, len = strlen (data), n;
+	char *buf, *ptr, *optr, *num;
+
+	if (len >= sizeof (w0)) {
+		return false;
+	}
+	// malloc can be slow here :?
+	if (!(buf = malloc (len + 1))) {
+		return false;
+	}
+	memcpy (buf, data, len + 1);
+	if (*buf) {
+		*w0 = *w1 = *w2 = *w3 = '\0';
+		ptr = strchr (buf, ' ');
+		if (!ptr) {
+			ptr = strchr (buf, '\t');
+		}
+		if (ptr) {
+			*ptr = '\0';
+			for (ptr++; *ptr == ' '; ptr++) {
+				;
+			}
+			strncpy (w0, buf, sizeof (w0) - 1);
+			strncpy (w1, ptr, sizeof (w1) - 1);
+
+			optr = ptr;
+			if (*ptr == '(') {
+				ptr = strchr (ptr+1, ')');
+			}
+			if (ptr && *ptr == '[') {
+				ptr = strchr (ptr+1, ']');
+			}
+			if (ptr && *ptr == '{') {
+				ptr = strchr (ptr+1, '}');
+			}
+			if (!ptr) {
+				eprintf ("Unbalanced bracket\n");
+				free (buf);
+				return false;
+			}
+			ptr = strchr (ptr, ',');
+			if (ptr) {
+				*ptr = '\0';
+				for (ptr++; *ptr == ' '; ptr++) {
+					;
+				}
+				strncpy (w1, optr, sizeof (w1) - 1);
+				strncpy (w2, ptr, sizeof (w2) - 1);
+				optr = ptr;
+				ptr = strchr (ptr, ',');
+				if (ptr) {
+					*ptr = '\0';
+					for (ptr++; *ptr == ' '; ptr++) {
+						;
+					}
+					strncpy (w2, optr, sizeof (w2) - 1);
+					strncpy (w3, ptr, sizeof (w3) - 1);
+				}
+			}
+			ptr = strchr (buf, '(');
+			if (ptr) {
+				*ptr = 0;
+				num = (char*)r_str_lchr (buf, ' ');
+				if (!num) {
+					num = (char *)r_str_lchr (buf, ',');
+				}
+				if (num) {
+					n = atoi (num + 1);
+					*ptr = '[';
+					r_str_cpy (num + 1, ptr);
+					ptr = (char*)r_str_lchr (buf, ']');
+					if (n && ptr) {
+						char *rest = strdup (ptr + 1);
+						size_t dist = len + 1 - (ptr - buf);
+						if (n > 0) {
+							snprintf (ptr, dist, "+%d]%s", n, rest);
+						} else {
+							snprintf (ptr, dist, "%d]%s", n, rest);
+						}
+						free (rest);
+					}
+				} else {
+					*ptr = '[';
+				}
+			}
+		}
+		{
+			const char *wa[] = { w0, w1, w2, w3 };
+			int nw = 0;
+			for (i = 0; i < 4; i++) {
+				if (wa[i][0]) {
+					nw++;
+				}
+			}
+			replace (nw, wa, str);
+		}
+	}
+	{
+		char *s = strdup (str);
+		s = r_str_replace (s, "+ -", "- ", 1);
+		s = r_str_replace (s, "- -", "+ ", 1);
+		strcpy (str, s);
+		free (s);
+	}
+	free (buf);
+	return true;
+}
